const b = ($input.first().json.body) || $input.first().json;
const score = Number(b.score) || 0;
const prioridad = b.prioridad || (score >= 8 ? 'Alta' : score >= 5 ? 'Media' : 'Baja');
const probabilidad = b.probabilidad || (score >= 8 ? 'Alta' : score >= 5 ? 'Media' : 'Baja');
const recordType = b.recordType || 'postulacion';
const iconUrl = recordType === 'email' 
  ? 'http://simonmarin.com/wp-content/uploads/2026/04/Correo-enviado.svg'
  : 'http://simonmarin.com/wp-content/uploads/2026/04/Busqueda-laboral.svg';
return [{ json: {
  chatId: b.chatId || '',
  jobTitle: b.jobTitle || b.cargo || 'Sin titulo',
  company: b.company || b.empresa || '',
  portal: b.portal || 'email',
  jobUrl: b.jobUrl || b.link || b.url || '',
  recipientEmail: b.recipientEmail || b.email || '',
  emailBody: b.emailBody || b.observaciones || '',
  emailSubject: b.emailSubject || b.subject || '',
  score: score,
  metodo: b.metodo || 'Email directo',
  region: b.region || 'R.M',
  notas: b.notas || b.observaciones || '',
  prioridad: prioridad,
  probabilidad: probabilidad,
  recordType: recordType,
  iconUrl: iconUrl,
  fecha: new Date().toISOString().split('T')[0]
}}];

